+            if (start != null && end != null) {
+                var locals = frames.get(eh.handler());
+                if (locals != null) {
+                    int slot = 0;
+                    for (var vti : locals) {
+                        if (vti == LONG || vti == DOUBLE) {
+                            markRange(slot, start, end + 1).flags |= 1;
+                            markRange(slot + 1, start, end + 1).flags |= 2;
+                            slot += 2;
+                        } else {
+                            if (vti != TOP) {
+                                markRange(slot, start, end + 1);
+                            }
+                            slot++;
+                        }
+                    }
+                }
+            }
+        }
